import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import UserRegister from "../users/userRegister";
import Login from "../users/Login";

export default function Navbar() {
  const navigate = useNavigate();

  const [role, setRole] = useState(localStorage.getItem("role"));
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user") || "{}")
  );

  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);
  const [openProfileMenu, setOpenProfileMenu] = useState(false);

  const menuRef = useRef();

  useEffect(() => {
    const sync = () => {
      setRole(localStorage.getItem("role"));
      setUser(JSON.parse(localStorage.getItem("user") || "{}"));
    };

    window.addEventListener("storage", sync);
    sync();

    return () => window.removeEventListener("storage", sync);
  }, []);

  const logout = () => {
    localStorage.clear();
    navigate("/");
    window.location.reload();
  };

  if (role === "Admin" || role === "Academic Panel") return null;

  return (
    <nav className="fixed top-0 w-full bg-gray-900 text-white z-50">

      <div className="flex justify-between p-4">

        <h1>Smart Learning</h1>

        {!role && (
          <div>
            <button onClick={() => setShowLogin(true)}>Login</button>
            <button onClick={() => setShowRegister(true)}>Sign Up</button>
          </div>
        )}

        {role && (
          <div ref={menuRef} className="relative">

            <img
              src={
                user?.profileImage ||
                "https://ui-avatars.com/api/?name=User"
              }
              className="w-10 h-10 rounded-full"
              onClick={() => setOpenProfileMenu(!openProfileMenu)}
            />

            {openProfileMenu && (
              <div className="absolute right-0 bg-white text-black">
                <button onClick={() => navigate("/profile")}>
                  Profile
                </button>
                <button onClick={logout}>Logout</button>
              </div>
            )}
          </div>
        )}

      </div>

      {showLogin && <Login closeModal={() => setShowLogin(false)} />}
      {showRegister && <UserRegister closeModal={() => setShowRegister(false)} />}
    </nav>
  );
}
